import ceylon.random {
    DefaultRandom,
    Random
}

shared void run() {
    """Demonstrates random number generation in Ceylon."""
    value rnd = DefaultRandom();

    // Random float between 0.0 and 1.0
    value randomFloat = rnd.nextFloat();
    print("Random Float [0.0-1.0): ``randomFloat``");

    // Random integer within a range [min, max]
    value min = 1;
    value max = 100;
    // nextInteger(limit) is exclusive, so we adjust the range size
    value randomInteger = min + rnd.nextInteger(max - min + 1);
    print("Random Integer [``min``-``max``]: ``randomInteger``");

    // Select a random element from a sequence
    value fruits = ["apple", "banana", "cherry"];
    if (exists randomFruit = fruits.getFrom(rnd.nextInteger(fruits.size))) {
        print("Random fruit: ``randomFruit``");
    }
}

