shared void run() {
    """Generates a Fibonacci sequence."""

    Integer fibonacci(Integer n) {
        if (n < 0) {
            throw Exception("Input must be non-negative");
        }
        if (n == 0) {
            return 0;
        }
        variable value a = 0;
        variable value b = 1;
        for (i in 2..n) {
            // Use tuple assignment for a clean swap
            {a, b} = {b, a + b};
        }
        return b;
    }

    value numTerms = 15;
    value sequence = (0...numTerms).map(fibonacci);

    print("First ``numTerms`` Fibonacci numbers:");
    print(sequence);

    // Ceylon's Integer is 64-bit, so it can handle a fairly large range.
    print("F(90) = ``fibonacci(90)``");
}

