shared void run() {
    """Calculates the factorial of a number."""

    Integer factorial(Integer n) {
        if (n < 0) {
            throw Exception("Factorial is not defined for negative numbers.");
        }
        variable value result = 1;
        for (i in 2..n) {
            result *= i;
        }
        return result;
    }

    value num = 5;
    print("Factorial of ``num`` is ``factorial(num)``");

    value numZero = 0;
    print("Factorial of ``numZero`` is ``factorial(numZero)``");

    // Ceylon's Integer (64-bit) overflows after 20!
    value numLarge = 20;
    print("Factorial of ``numLarge`` is ``factorial(numLarge)``");
}

