import ceylon.math.float {
    power
}

shared void run() {
    """Checks if a number is prime."""

    Boolean isPrime(Integer n) {
        if (n <= 1) {
            return false;
        }
        if (n <= 3) {
            return true;
        }
        if (n % 2 == 0 || n % 3 == 0) {
            return false;
        }

        value limit = power(n.float, 0.5).integer;
        variable value i = 5;
        while (i <= limit) {
            if (n % i == 0 || n % (i + 2) == 0) {
                return false;
            }
            i += 6;
        }
        return true;
    }

    value numbersToCheck = [2, 3, 4, 17, 25, 29, 97, 100, 1, 104729];
    for (num in numbersToCheck) {
        if (isPrime(num)) {
            print("``num`` is prime.");
        } else {
            print("``num`` is not prime.");
        }
    }
}

