import java.io {
    File, 
    BufferedReader,
    FileReader,
    PrintWriter
}

shared void run() {
    """Reads a text file line by line using Java interop."""
    value filename = "ceylon_read_test.txt";
    value file = File(filename);

    // Create a dummy file for reading
    try (PrintWriter writer = new PrintWriter(file)) {
        writer.println("First line from Ceylon.");
        writer.println("Second line.");
    } catch (Exception e) {
        print("Error creating dummy file: ``e.message``");
        return;
    }

    print("--- Reading file '``filename``' ---");
    try (BufferedReader reader = new BufferedReader(new FileReader(file))) {
        variable value line = reader.readLine();
        while (exists line) {
            print(line);
            line = reader.readLine();
        }
    } catch (Exception e) {
        print("Error reading file: ``e.message``");
    }
}

