import java.io {
    File,
    FileWriter,
    PrintWriter
}

shared void run() {
    """Writes and appends to a text file using Java interop."""
    value filename = "output_ceylon.txt";
    value file = File(filename);

    // 1. Overwrite or create a new file
    print("--- Writing (Overwrite) to '``filename``' ---");
    try (PrintWriter writer = new PrintWriter(FileWriter(file))) {
        writer.println("This line overwrites existing content.");
        writer.println("Written from a Ceylon program.");
        print("Content written successfully.");
    } catch (Exception e) {
        print("Error writing to file: ``e.message``");
    }

    // 2. Append to the existing file
    print("\n--- Appending to '``filename``' ---");
    try (PrintWriter writer = new PrintWriter(FileWriter(file, true))) { // 'true' for append mode
        writer.println("--- Appended Content ---");
        writer.println("This line was appended.");
        print("Content appended successfully.");
    } catch (Exception e) {
        print("Error appending to file: ``e.message``");
    }
}

