import java.io { File }

shared void run() {
    """Checks if a file or directory exists using Java interop."""

    value fileToCheck = "ceylon.json"; // Should exist
    value dirToCheck = "."; // Current directory
    value nonExistent = "no_such_file.ceylon";

    void checkPath(String path) {
        value item = File(path);
        print("\nChecking '``path``':");
        if (item.exists()) {
            print("  -> Exists: true");
            print("  -> Is File: ``item.isFile()``");
            print("  -> Is Directory: ``item.isDirectory()``");
        } else {
            print("  -> Exists: false");
        }
    }

    checkPath(fileToCheck);
    checkPath(dirToCheck);
    checkPath(nonExistent);
}

