import ceylon.time {
    now,
    parisTimeZone,
    londonTimeZone,
    newYorkTimeZone
}
import ceylon.time.format {
    format
}

shared void run () {
    """Demonstrates date and time functions in Ceylon."""

    value instant = now();
    print("Current Instant (UTC): ``instant``");

    // Create zoned instances
    value localNow = instant.inZone(parisTimeZone); // Example local timezone
    value newYorkNow = instant.inZone(newYorkTimeZone);

    print("Local Time (Paris): ``localNow``");
    print("New York Time: ``newYorkNow``");

    print("\n--- Components ---");
    print("Year: ``localNow.year``, Month: ``localNow.month``, Day: ``localNow.day``");
    print("Hour: ``localNow.hour``, Minute: ``localNow.minute``, Second: ``localNow.second``");

    print("\n--- Formatting ---");
    // See Ceylon SDK for pattern letters
    value pattern = "yyyy-MM-dd HH:mm:ss Z";
    print("Custom format '``pattern``': ``format(pattern, localNow)``");

    value readablePattern = "EEEE, MMMM d, yyyy";
    print("Readable format: ``format(readablePattern, localNow)``");

    print("\n--- Epoch Time ---");
    print("Seconds since epoch: ``instant.seconds``");
    print("Milliseconds since epoch: ``instant.milliseconds``");
}

